require "array"
require "math"

def solve(nums : Array(Int64)) : Int64
  ones_indices = Array(Int64).new
  twos_indices = Array(Int64).new

  for i in nums.size - 1.d.downto 0 {
    val = nums[i.i]
    if val == 1 {
      ones_indices.push(i)
    } else if val == 2 {
      twos_indices.push(i)
    }
  }

  if ones_indices.size == 0 || twos_indices.size == 0 {
    return -1
  }

  min_diff = Int64.max_value

  ones_indices.each do |i|
    twos_indices.each do |j|
      diff = (i - j).abs
      if diff < min_diff {
        min_diff = diff
      }
    end
  end

  min_diff
end
